// Format transcript with speaker labels
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the call recording URL is valid and publicly accessible.');
}

const formattedTranscript = segments
  .map(s => {
    const ms = Math.floor(s.start / 1000);
    const mm = Math.floor(ms / 60);
    const ss = ms % 60;
    return `[${s.speaker} | ${mm}:${ss.toString().padStart(2,'0')}] ${s.text.trim()}`;
  })
  .join('\n');

const totalMinutes = Math.round((segments[segments.length - 1]?.end || 0) / 60000);
const speakers = [...new Set(segments.map(s => s.speaker))];
const wordCount = segments.map(s => s.text).join(' ').split(/\s+/).length;

// Form data
const agentName = $('1. Form — Support Call + Details').item.json['Agent Name'];
const customerName = $('1. Form — Support Call + Details').item.json['Customer Name'];
const customerEmail = $('1. Form — Support Call + Details').item.json['Customer Email'];
const issueCategory = $('1. Form — Support Call + Details').item.json['Issue Category'];
const callDate = $('1. Form — Support Call + Details').item.json['Call Date'];
const productName = $('1. Form — Support Call + Details').item.json['Product / Service Name'];
const recordingUrl = $('1. Form — Support Call + Details').item.json['Call Recording URL'];

return [{
  json: {
    formattedTranscript,
    totalMinutes,
    wordCount,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    agentName,
    customerName,
    customerEmail,
    issueCategory,
    callDate,
    productName,
    recordingUrl
  }
}];

// Parse AI support analysis output
const output = $input.first().json.output || '';

const subjectMatch = output.match(/TICKET_SUBJECT:\s*([\s\S]*?)(?=\nISSUE_SUMMARY:|$)/);
const issueSummaryMatch = output.match(/ISSUE_SUMMARY:\s*([\s\S]*?)(?=\nROOT_CAUSE:|$)/);
const rootCauseMatch = output.match(/ROOT_CAUSE:\s*([\s\S]*?)(?=\nRESOLUTION_GIVEN:|$)/);
const resolutionMatch = output.match(/RESOLUTION_GIVEN:\s*([\s\S]*?)(?=\nFOLLOW_UP_REQUIRED:|$)/);
const followUpMatch = output.match(/FOLLOW_UP_REQUIRED:\s*([\s\S]*?)(?=\nKEY_QUOTES:|$)/);
const quotesMatch = output.match(/KEY_QUOTES:\s*([\s\S]*?)(?=\nSENTIMENT:|$)/);
const sentimentMatch = output.match(/SENTIMENT:\s*([\s\S]*?)(?=\nPRIORITY:|$)/);
const priorityMatch = output.match(/PRIORITY:\s*([\s\S]*?)(?=\nCSAT_PREDICTION:|$)/);
const csatMatch = output.match(/CSAT_PREDICTION:\s*([\d.]+)/);
const tagsMatch = output.match(/TAGS:\s*([\s\S]*)$/);

const ticketSubject = subjectMatch ? subjectMatch[1].trim() : `Support Call — ${$('7. Code — Format Transcript').item.json.issueCategory}`;
const issueSummary = issueSummaryMatch ? issueSummaryMatch[1].trim() : '';
const rootCause = rootCauseMatch ? rootCauseMatch[1].trim() : '';
const resolution = resolutionMatch ? resolutionMatch[1].trim() : '';
const followUp = followUpMatch ? followUpMatch[1].trim() : 'None';
const keyQuotes = quotesMatch ? quotesMatch[1].trim() : '';
const sentiment = sentimentMatch ? sentimentMatch[1].trim() : 'Neutral';
const priority = priorityMatch ? priorityMatch[1].trim() : 'Normal';
const csatPrediction = csatMatch ? parseFloat(csatMatch[1]) : 3;
const tags = tagsMatch ? tagsMatch[1].trim() : '';

// Map priority to Zendesk priority
const priorityMap = { 'urgent': 'urgent', 'high': 'high', 'normal': 'normal', 'low': 'low' };
const zendeskPriority = priorityMap[priority.toLowerCase()] || 'normal';

// Get call data
const callData = $('7. Code — Format Transcript').item.json;

// Build Zendesk ticket body
const ticketBody = [
  `SUPPORT CALL SUMMARY`,
  `Agent: ${callData.agentName} | Customer: ${callData.customerName} | Date: ${callData.callDate} | Duration: ${callData.totalMinutes} min`,
  `Recording: ${callData.recordingUrl}`,
  ``,
  `ISSUE SUMMARY`,
  issueSummary,
  ``,
  `ROOT CAUSE`,
  rootCause,
  ``,
  `RESOLUTION GIVEN`,
  resolution,
  ``,
  `FOLLOW-UP REQUIRED`,
  followUp,
  ``,
  `KEY QUOTES FROM CUSTOMER`,
  keyQuotes,
  ``,
  `CALL INTELLIGENCE`,
  `Sentiment: ${sentiment} | Priority: ${priority} | CSAT Prediction: ${csatPrediction}/5`,
  ``,
  `TAGS`,
  tags
].join('\n');

return [{
  json: {
    ticketSubject,
    ticketBody,
    issueSummary,
    rootCause,
    resolution,
    followUp,
    keyQuotes,
    sentiment,
    priority,
    zendeskPriority,
    csatPrediction,
    tags,
    agentName: callData.agentName,
    customerName: callData.customerName,
    customerEmail: callData.customerEmail,
    issueCategory: callData.issueCategory,
    callDate: callData.callDate,
    productName: callData.productName,
    recordingUrl: callData.recordingUrl,
    totalMinutes: callData.totalMinutes
  }
}];
